addPlacement({
  id: "auth.profile.widget",
  slot: "app.top-right",
  surface: "*",
  order: 1000,
  componentToken: "auth.web.profile.widget"
});

addPlacement({
  id: "auth.profile.menu.surface-switch",
  slot: "avatar.primary-menu",
  surface: "*",
  order: 100,
  componentToken: "auth.web.profile.menu.surface-switch-item",
  when: ({ auth }) => Boolean(auth?.authenticated)
});

addPlacement({
  id: "auth.profile.menu.sign-in",
  slot: "avatar.primary-menu",
  surface: "*",
  order: 200,
  componentToken: "auth.web.profile.menu.link-item",
  props: {
    label: "Sign in",
    to: "/auth/login"
  },
  when: ({ auth }) => !Boolean(auth?.authenticated)
});

addPlacement({
  id: "auth.profile.menu.sign-out",
  slot: "avatar.primary-menu",
  surface: "*",
  order: 1000,
  componentToken: "auth.web.profile.menu.link-item",
  props: {
    label: "Sign out",
    to: "/auth/signout"
  },
  when: ({ auth }) => Boolean(auth?.authenticated)
});

config.tenancyMode = "workspace";
config.workspaceSwitching = true;
config.workspaceInvites = true;
config.workspaceCreateEnabled = false;
config.assistantEnabled = false;
config.assistantRequiredPermission = "";
config.socialEnabled = false;
config.socialFederationEnabled = false;
config.surfaceDefinitions = config.surfaceDefinitions || {};
const enabledSurfaceIds = Object.keys(config.surfaceDefinitions).filter(
  (surfaceId) => config.surfaceDefinitions[surfaceId] && config.surfaceDefinitions[surfaceId].enabled !== false
);
const preferredWorkspaceSurfaceIds = ["app", "admin"];
for (const surfaceId of preferredWorkspaceSurfaceIds) {
  if (config.surfaceDefinitions[surfaceId] && config.surfaceDefinitions[surfaceId].enabled !== false) {
    config.surfaceDefinitions[surfaceId].requiresWorkspace = true;
  }
}
const hasWorkspaceSurface = enabledSurfaceIds.some(
  (surfaceId) => config.surfaceDefinitions[surfaceId] && config.surfaceDefinitions[surfaceId].requiresWorkspace === true
);
if (!hasWorkspaceSurface && enabledSurfaceIds.length > 0) {
  config.surfaceDefinitions[enabledSurfaceIds[0]].requiresWorkspace = true;
}

addPlacement({
  id: "users.workspace.selector",
  slot: "app.top-left",
  surface: "*",
  order: 200,
  componentToken: "users.web.workspace.selector",
  props: {
    allowOnNonWorkspaceSurface: true,
    targetSurfaceId: "app"
  },
  when: ({ auth }) => {
    return Boolean(auth?.authenticated);
  }
});

